IF(
AND(ISBLANK(Last_Activity_Date_by_MIR__c),ISBLANK(Last_Activity_Date_by_GTM__c)), NULL,
IF(
OR(
Last_Activity_Date_by_MIR__c >= Last_Activity_Date_by_GTM__c,
AND(
NOT(ISBLANK(Last_Activity_Date_by_MIR__c)),
ISBLANK(Last_Activity_Date_by_GTM__c)
)
),
Last_Activity_Date_by_MIR__c, Last_Activity_Date_by_GTM__c
)
)
